@app.function_name(name="JobProcessor")
@app.service_bus_queue_trigger(
    arg_name="msg",
    queue_name="job-queue",
    connection="SERVICE_BUS_CONNECTION"
)
def process_job_queue(msg: func.ServiceBusMessage) -> None:
    """
    Azure Function that processes async job messages from Service Bus.
    
    Expected message format (JSON):
    {
        "job_id": "unique-id",
        "job_type": "data_transform",
        "params": { ... },
        "submitted_at": "2024-01-01T00:00:00Z"
    }
    """
    message_id = msg.message_id
    logging.info(f"Processing message: {message_id}")

    try:
        # Safely deserialize using JSON (NOT pickle)
        raw_body = msg.get_body().decode("utf-8")
        job = deserialize_job(raw_body)

        # Validate required fields
        required_fields = {"job_id", "job_type", "params"}
        missing_fields = required_fields - set(job.keys())
        if missing_fields:
            raise ValueError(f"Missing required fields: {missing_fields}")

        job_id = job["job_id"]
        job_type = job["job_type"]
        params = job["params"]

        logging.info(
            f"Job {job_id} | Type: {job_type} | "
            f"Submitted: {job.get('submitted_at', 'unknown')} | "
            f"Enqueued: {msg.enqueued_time_utc}"
        )

        # Dispatch to registered handler (allowlist pattern)
        handler = JOB_HANDLERS.get(job_type)
        if handler is None:
            raise ValueError(
                f"Unknown job type: '{job_type}'. "
                f"Registered types: {list(JOB_HANDLERS.keys())}"
            )

        result = handler(params)

        logging.info(f"Job {job_id} completed successfully. Result: {result}")

    except json.JSONDecodeError as e:
        logging.error(f"Message {message_id}: Invalid JSON - {e}")
        raise  # Let Service Bus handle dead-lettering

    except ValueError as e:
        logging.error(f"Message {message_id}: Validation error - {e}")
        raise

    except Exception as e:
        logging.error(f"Message {message_id}: Processing failed - {e}")
        raise


